    #region Client

    /// <summary>
    /// Typed client for etsy connector.
    /// </summary>
    public class EtsyClient : ConnectorClientBase
    {
        /// <summary>
        /// Creates a new EtsyClient with the specified connection runtime URL.
        /// Uses <see cref="ManagedIdentityCredential"/> by default.
        /// </summary>
        /// <param name="connectionRuntimeUrl">The connection runtime URL from Azure Portal.</param>
        public EtsyClient(Uri connectionRuntimeUrl)
            : base(connectionRuntimeUrl)
        {
        }

        /// <summary>
        /// Creates a new EtsyClient with the specified connection runtime URL and credential.
        /// </summary>
        /// <param name="connectionRuntimeUrl">The connection runtime URL from Azure Portal.</param>
        /// <param name="credential">The Azure credential for authentication.</param>
        /// <param name="options">Optional client options for retry, timeout, etc.</param>
        public EtsyClient(Uri connectionRuntimeUrl, TokenCredential credential, ConnectorClientOptions options = null)
            : base(connectionRuntimeUrl, credential, options)
        {
        }

        /// <summary>
        /// Creates a new EtsyClient with the specified connection runtime URL and credential.
        /// </summary>
        /// <param name="connectionRuntimeUrl">The connection runtime URL from Azure Portal.</param>
        /// <param name="credential">The Azure credential for authentication.</param>
        public EtsyClient(Uri connectionRuntimeUrl, TokenCredential credential)
            : base(connectionRuntimeUrl, credential)
        {
        }

        /// <summary>
        /// Creates a new EtsyClient with the specified connection runtime URL string.
        /// Uses <see cref="ManagedIdentityCredential"/> by default.
        /// </summary>
        /// <param name="connectionRuntimeUrl">The connection runtime URL from Azure Portal.</param>
        public EtsyClient(string connectionRuntimeUrl)
            : base(connectionRuntimeUrl)
        {
        }

        protected EtsyClient() : base() { }

        public override string ConnectorName => "etsy";

        /// <summary>
        /// Ping
        /// </summary>
        /// <remarks>Check to confirm connectivity to the Etsy API with an application.</remarks>
        /// <param name="cancellationToken">Cancellation token.</param>
        /// <returns>The Ping response.</returns>
        public virtual async Task<Pong> PingAsync(CancellationToken cancellationToken = default)
        {
            var path = $"/openapi-ping";
            return await this
                .CallConnectorAsync<Pong>(HttpMethod.Get, path, cancellationToken: cancellationToken)
                .ConfigureAwait(continueOnCapturedContext: false);
        }

        /// <summary>
        /// Get a shop payment account ledger&apos;s entries
        /// </summary>
        /// <remarks>Retrieve the entries of a shop&apos;s payment account ledger.</remarks>
        /// <param name="shopId">Shop ID</param>
        /// <param name="minimumCreated">Minimum Created</param>
        /// <param name="maximumCreated">Maximum Created</param>
        /// <param name="limit">Limit</param>
        /// <param name="offset">Offset</param>
        /// <param name="cancellationToken">Cancellation token.</param>
        /// <returns>The Get a shop payment account ledger&apos;s entries response.</returns>
        public virtual async Task<PaymentAccountLedgerEntries> PaymentLedgerEntriesAsync(int shopId, int minimumCreated, int maximumCreated, int? limit = default, int? offset = default, CancellationToken cancellationToken = default)
